import app from 'flarum/forum/app';
import Page from 'flarum/common/components/Page';
import LoadingIndicator from 'flarum/common/components/LoadingIndicator';
import GroupHero from './GroupHero';
import GroupDiscussionList from './GroupDiscussionList';
import MemberList from './MemberList';
import EditGroupModal from './EditGroupModal';
export default class GroupPage extends Page {
  oninit(vnode) {
    super.oninit(vnode);
    this.group = null;
    this.loading = true;
    this.error = null;
  }
  oncreate(vnode) {
    super.oncreate(vnode);
    this.loadGroup(vnode.attrs.slug);
  }
  onupdate(vnode) {
    if (vnode.attrs.slug !== this.attrs.slug) {
      this.group = null;
      this.loading = true;
      this.error = null;
      this.loadGroup(vnode.attrs.slug);
    }
  }
  loadGroup(slug) {
    app.store.find('social-groups', {
      filter: {
        slug
      },
      include: 'user',
      'page[limit]': 1
    }).then(groups => {
      const group = groups[0] || null;
      this.group = group;
      this.loading = false;
      if (group) {
        document.title = "".concat(group.name(), " \u2014 ").concat(app.forum.attribute('title'));
      }
      m.redraw();
    }).catch(() => {
      this.error = 'Failed to load group.';
      this.loading = false;
      m.redraw();
    });
  }
  join() {
    if (!this.group) return;
    fetch("".concat(app.forum.attribute('apiUrl'), "/social-groups/").concat(this.group.id(), "/join"), {
      method: 'POST',
      headers: {
        'X-CSRF-Token': app.session.csrfToken || ''
      }
    }).then(r => r.json()).then(data => {
      this.group.pushData({
        attributes: {
          isMember: true,
          memberCount: data.memberCount
        }
      });
      m.redraw();
    });
  }
  leave() {
    if (!this.group) return;
    fetch("".concat(app.forum.attribute('apiUrl'), "/social-groups/").concat(this.group.id(), "/join"), {
      method: 'DELETE',
      headers: {
        'X-CSRF-Token': app.session.csrfToken || ''
      }
    }).then(r => r.json()).then(data => {
      this.group.pushData({
        attributes: {
          isMember: false,
          memberCount: data.memberCount
        }
      });
      m.redraw();
    });
  }
  view() {
    if (this.loading) {
      return m('.GroupPage', m('.GroupPage-loading', m(LoadingIndicator, {
        display: 'block'
      })));
    }
    if (this.error || !this.group) {
      return m('.GroupPage', m('.container', m('p.GroupPage-error', this.error || 'Group not found.')));
    }
    const group = this.group;
    const isMember = group.isMember();
    return m('.GroupPage', [
    // Hero: banner + avatar + name + join/edit buttons
    m(GroupHero, {
      group,
      onJoin: () => this.join(),
      onLeave: () => this.leave(),
      onEdit: () => app.modal.show(EditGroupModal, {
        group,
        onSaved: updated => {
          group.pushData({
            attributes: updated
          });
          m.redraw();
        }
      })
    }),
    // Two-column body
    m('.GroupPage-body', [
    // Main column — discussion feed
    m('.GroupPage-main', [m(GroupDiscussionList, {
      groupId: group.id(),
      groupSlug: group.slug(),
      isMember
    })]),
    // Sidebar — about + members
    m('.GroupPage-sidebar', [m('.GroupPage-aboutCard', [m('.GroupPage-aboutCard-title', app.translator.trans('ernestdefoe-social-groups.forum.group.about_title')), group.description() ? m('p.GroupPage-aboutCard-text', group.description()) : m('p.GroupPage-aboutCard-empty', app.translator.trans('ernestdefoe-social-groups.forum.group.description_placeholder')), group.isPrivate() ? m('.GroupPage-privateTag', [m('i.fas.fa-lock'), ' ', app.translator.trans('ernestdefoe-social-groups.forum.groups.private')]) : null]), m(MemberList, {
      groupId: group.id()
    })])])]);
  }
}
flarum.reg.add('ernestdefoe-social-groups', 'forum/components/GroupPage', GroupPage);